vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    vec2 d = uTexSize.zw * 8;
    vec3 dx = ( GetBlur1(vUvOriginal + vec2(1,0)*d) - GetBlur1(vUvOriginal-vec2(1,0)*d) );
    vec3 dy = ( GetBlur1(vUvOriginal + vec2(0,1)*d) - GetBlur1(vUvOriginal-vec2(0,1)*d) );

ret.y = tex2d(sampler_fc_main, fract(vUv + vec2(dx.y,dy.y)*uTexSize.zw*4)).y;
vec2 dither_uv = vUvOriginal*uTexSize.xy*texsize_noise_lq.zw * 1.2 + rand_frame.xy;
ret.y += (texture(sampler_noise_lq, dither_uv).xyz-0.5) *0.0 - 0.004;
ret = 0;
ret.y = tex2d(sampler_fc_main, fract(vUv)).y;
ret.y += (ret.y - GetBlur3(fract(vUv)).y -0.03)*.6 - 0.06;
ret.y += GetBlur3(vUvOriginal).x*0.3;

ret.z = tex2d(sampler_fc_main,mix(vUvOriginal,vUv,0.3) + vec2(dx.z,dy.z)*uTexSize.zw*8).z - 0.03;
ret.z += clamp01(0.2-GetBlur2(vUv).y)*0.1 + GetBlur2(vUvOriginal).x*0.2;


